    user.username = "john.employee"
    user.role = "employee"
    user.is_authenticated = True
    return user


@pytest.fixture
def unauthenticated_user():
    """Return an unauthenticated user."""
    user = MagicMock()
    user.id = None
    user.username = None
    user.role = None
    user.is_authenticated = False
    return user


@pytest.fixture
def valid_department_data():
    """Return a complete, valid department form payload."""
    return {
        "name": "Engineering",
        "code": "ENG",
        "cost_center": "CC-001",
        "manager_id": 42,
    }


@pytest.fixture
def department_service(tmp_path):
    """
    Provide a lightweight fake DepartmentService backed by an in-memory store
    so that tests are hermetic and do not require a live database.
    """
    from unittest.mock import MagicMock

    service = MagicMock()
    _store = {}
    _audit_log = []

    def _create(data, created_by):
        dept = MagicMock()
        dept.id = len(_store) + 1
        dept.name = data["name"]
        dept.code = data["code"]
        dept.cost_center = data.get("cost_center")
        dept.manager_id = data.get("manager_id")
        dept.created_by = created_by
        dept.created_at = datetime.utcnow()
        _store[dept.id] = dept

        audit = MagicMock()
        audit.entity = "Department"
        audit.entity_id = dept.id
        audit.action = "CREATE"
        audit.performed_by = created_by
        audit.timestamp = dept.created_at
        _audit_log.append(audit)

        return dept

    service.create.side_effect = _create
    service._store = _store
    service._audit_log = _audit_log
    return service


@pytest.fixture
def audit_service():
    """Return a mock audit service for verification."""
    return MagicMock()


# ---------------------------------------------------------------------------
# Helper – simulate the application layer under test
# ---------------------------------------------------------------------------

class DepartmentFormError(Exception):
    """Raised when form validation fails."""
    def __init__(self, errors: dict):
        self.errors = errors
        super().__init__(str(errors))


class PermissionError(Exception):
    """Raised when the user lacks required permissions."""


class AuthenticationError(Exception):
    """Raised when the user is not authenticated."""


def create_department_use_case(form_data: dict, current_user, dept_service, audit_service):
    """
    Thin application-layer function that mirrors what the UI controller calls.
    Raises typed exceptions so tests can assert on failure modes.
    Returns the newly created department on success.
    """
    # --- authentication guard ---
    if not current_user.is_authenticated:
        raise AuthenticationError("User must be logged in.")

    # --- authorisation guard ---
    if current_user.role != "manager":
        raise PermissionError("Only managers may create departments.")

    # --- mandatory field validation ---
    mandatory = ["name", "code"]
    errors = {}
    for field in mandatory:
        value = form_data.get(field, "")
        if not value or not str(value).strip():
            errors[field] = f"{field} is required."

    # name length constraint
    if "name" not in errors and len(form_data["name"].strip()) > 100:
        errors["name"] = "name must not exceed 100 characters."

    # code format constraint (uppercase letters / digits / hyphens, 2–10 chars)
    import re
    if "code" not in errors:
        if not re.fullmatch(r"[A-Z0-9\-]{2,10}", form_data["code"].strip()):
            errors["code"] = "code must be 2-10 uppercase alphanumeric characters or hyphens."

    if errors:
        raise DepartmentFormError(errors)

    # --- persist ---
    dept = dept_service.create(form_data, created_by=current_user.id)

    # --- audit ---
    audit_service.log(
        entity="Department",
        entity_id=dept.id,
        action="CREATE",
        performed_by=current_user.id,
    )

    return dept


# ===========================================================================
# Test Classes
# ===========================================================================

class TestAuthentication:
    """Gate: unauthenticated users must NOT reach the create flow."""

    def test_unauthenticated_user_cannot_create_department(
        self, unauthenticated_user, valid_department_data,
        department_service, audit_service
    ):
        with pytest.raises(AuthenticationError):
            create_department_use_case(
                valid_department_data, unauthenticated_user,
                department_service, audit_service
            )

    def test_unauthenticated_user_does_not_trigger_persistence(
        self, unauthenticated_user, valid_department_data,
        department_service, audit_service
    ):
        with pytest.raises(AuthenticationError):
            create_department_use_case(
                valid_department_data, unauthenticated_user,
                department_service, audit_service
            )
        department_service.create.assert_not_called()

    def test_unauthenticated_user_does_not_write_audit(
        self, unauthenticated_user, valid_department_data,
        department_service, audit_service
    ):
        with pytest.raises(AuthenticationError):
            create_department_use_case(
                valid_department_data, unauthenticated_user,
                department_service, audit_service
            )
        audit_service.log.assert_not_called()


