class TestMandatoryFieldValidation:
    """
    Every mandatory field must be individually rejected when absent or blank.
    No persistence or audit side-effects should occur on validation failure.
    """

    @pytest.mark.parametrize("missing_field", ["name", "code"])
    def test_missing_mandatory_field_raises_form_error(
        self, manager_user, valid_department_data,
        department_service, audit_service, missing_field
    ):
        data = {**valid_department_data}
        del data[missing_field]
        with pytest.raises(DepartmentFormError) as exc_info:
            create_department_use_case(
                data, manager_user, department_service, audit_service
            )
        assert missing_field in exc_info.value.errors

    @pytest.mark.parametrize("blank_value", ["", "   ", "\t", "\n"])
    def test_blank_name_fails_validation(
        self, manager_user, valid_department_data,
        department_service, audit_service, blank_value
    ):
        data = {**valid_department_data, "name": blank_value}
        with pytest.raises(DepartmentFormError) as exc_info:
            create_department_use_case(
                data, manager_user, department_service, audit_service
            )
        assert "name" in exc_info.value.errors

    @pytest.mark.parametrize("blank_value", ["", "   "])
    def test_blank_code_fails_validation(
        self, manager_user, valid_department_data,
        department_service, audit_service, blank_value
    ):
        data = {**valid_department_data, "code": blank_value}
        with pytest.raises(DepartmentFormError) as exc_info:
            create_department_use_case(
                data, manager_user, department_service, audit_service
            )
        assert "code" in exc_info.value.errors

    def test_multiple_missing_fields_returns_all_errors(
        self, manager_user, department_service, audit_service
    ):
        data = {"cost_center": "CC-999"}  # name and code both absent
        with pytest.raises(DepartmentFormError) as exc_info:
            create_department_use_case(
                data, manager_user, department_service, audit_service
            )
        assert "name" in exc_info.value.errors
        assert "code" in exc_info.value.errors

    def test_name_exceeding_max_length_fails_validation(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        data = {**valid_department_data, "name": "A" * 101}
        with pytest.raises(DepartmentFormError) as exc_info:
            create_department_use_case(
                data, manager_user, department_service, audit_service
            )
        assert "name" in exc_info.value.errors

    @pytest.mark.parametrize("invalid_code", [
        "eng",           # lowercase
        "E",             # too short
        "ENGINEERING1234",  # too long
        "ENG 01",        # contains space
        "ENG@01",        # special character
    ])
    def test_invalid_code_format_fails_validation(
        self, manager_user, valid_department_data,
        department_service, audit_service, invalid_code
    ):
        data = {**valid_department_data, "code": invalid_code}
        with pytest.raises(DepartmentFormError) as exc_info:
            create_department_use_case(
                data, manager_user, department_service, audit_service
            )
        assert "code" in exc_info.value.errors

    @pytest.mark.parametrize("missing_field", ["name", "code"])
    def test_validation_failure_does_not_persist_department(
        self, manager_user, valid_department_data,
        department_service, audit_service, missing_field
    ):
        data = {**valid_department_data}
        del data[missing_field]
        with pytest.raises(DepartmentFormError):
            create_department_use_case(
                data, manager_user, department_service, audit_service
            )
        department_service.create.assert_not_called()

    @pytest.mark.parametrize("missing_field", ["name", "code"])
    def test_validation_failure_does_not_write_audit(
        self, manager_user, valid_department_data,
        department_service, audit_service, missing_field
    ):
        data = {**valid_department_data}
        del data[missing_field]
        with pytest.raises(DepartmentFormError):
            create_department_use_case(
                data, manager_user, department_service, audit_service
            )
        audit_service.log.assert_not_called()


class TestSuccessfulCreation:
    """Happy-path: manager submits valid data → department created + audit written."""

