class TestAuditRecord:
    """An audit record must be written on every successful creation."""

    def test_audit_log_called_on_success(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        create_department_use_case(
            valid_department_data, manager_user,
            department_service, audit_service
        )
        audit_service.log.assert_called_once()

    def test_audit_record_references_correct_entity(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        create_department_use_case(
            valid_department_data, manager_user,
            department_service, audit_service
        )
        _, kwargs = audit_service.log.call_args
        assert kwargs["entity"] == "Department"

    def test_audit_record_action_is_create(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        create_department_use_case(
            valid_department_data, manager_user,
            department_service, audit_service
        )
        _, kwargs = audit_service.log.call_args
        assert kwargs["action"] == "CREATE"

    def test_audit_record_references_new_department_id(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        dept = create_department_use_case(
            valid_department_data, manager_user,
            department_service, audit_service
        )
        _, kwargs = audit_service.log.call_args
        assert kwargs["entity_id"] == dept.id

    def test_audit_record_records_performing_user(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        create_department_use_case(
            valid_department_data, manager_user,
            department_service, audit_service
        )
        _, kwargs = audit_service.log.call_args
        assert kwargs["performed_by"] == manager_user.id

    def test_audit_record_written_after_successful_persistence(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        """Verify ordering: persist first, then audit."""
        call_order = []
        department_service.create.side_effect = (
            lambda data, created_by: (
                call_order.append("create"),
                MagicMock(id=1, name=data["name"], code=data["code"],
                          cost_center=data.get("cost_center"),
                          manager_id=data.get("manager_id"),
                          created_by=created_by,
                          created_at=datetime.utcnow())
            )[-1]
        )
        audit_service.log.side_effect = lambda **kw: call_order.append("audit")

        create_department_use_case(
            valid_department_data, manager_user,
            department_service, audit_service
        )
        assert call_order == ["create", "audit"], (
            "Audit must be written after the department is persisted."
        )

    def test_no_audit_written_when_persistence_fails(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        """If the DB write fails, no audit record should be emitted."""
        department_service.create.side_effect = RuntimeError("DB unavailable")

        with pytest.raises(RuntimeError):
            create_department_use_case(
                valid_department_data, manager_user,
                department_service, audit_service
            )
        audit_service.log.assert_not_called()


class TestIdempotencyAndEdgeCases:
    """Edge cases that a quality engineer should probe."""

    def test_name_at_maximum_allowed_length_succeeds(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        data = {**valid_department_data, "name": "A" * 100}
