            )
        assert audit_service.log.call_count == 2

    def test_return_value_is_the_persisted_department(
        self, manager_user, valid_department_data,
        department_service, audit_service
    ):
        """Use-case must return the domain object, not None."""
        result = create_department_use_case(
            valid_department_data, manager_user,
            department_service, audit_service
        )
        assert result is not None
        assert hasattr(result, "id")
